export async function addShowToList(
  listId: string,
  show: {
    tmdb_id: number;
    title: string;
    poster_path: string | null;
    first_air_date?: string;
    overview?: string;
  },
) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Unauthorized");

  // Upsert show in shows table
  let { data: existingShow } = await supabase
    .from("shows")
    .select("id")
    .eq("tmdb_id", show.tmdb_id)
    .single();

  if (!existingShow) {
    const { data: newShow, error: showError } = await supabase
      .from("shows")
      .insert({
        tmdb_id: show.tmdb_id,
        title: show.title,
        poster_path: show.poster_path,
        first_air_date: show.first_air_date || null,
        overview: show.overview || null,
      })
      .select()
      .single();

    if (showError) throw new Error(showError.message);
    existingShow = newShow;
  }

  // Get max position in list
  const { data: items } = await supabase
    .from("list_items")
    .select("position")
    .eq("list_id", listId)
    .order("position", { ascending: false })
    .limit(1);

  const nextPosition = (items?.[0]?.position ?? -1) + 1;

  const { error } = await supabase.from("list_items").insert({
    list_id: listId,
    show_id: existingShow!.id,
    position: nextPosition,
  });

  if (error) throw new Error(error.message);

  revalidatePath(`/lists/${listId}`);
}

export async function removeShowFromList(listId: string, itemId: string) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Unauthorized");

  const { error } = await supabase.from("list_items").delete().eq("id", itemId);

  if (error) throw new Error(error.message);

  revalidatePath(`/lists/${listId}`);
}

export async function updateShowRating(
  listId: string,
  itemId: string,
  rating: number,
) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Unauthorized");

  if (rating < 1 || rating > 10) throw new Error("Rating must be 1-10");

  const { error } = await supabase
    .from("list_items")
    .update({ rating })
    .eq("id", itemId);

  if (error) throw new Error(error.message);

  revalidatePath(`/lists/${listId}`);
}

export async function reorderListItems(listId: string, itemIds: string[]) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Unauthorized");

  // Update positions
  const updates = itemIds.map((id, index) =>
    supabase.from("list_items").update({ position: index }).eq("id", id),
  );

  await Promise.all(updates);

  revalidatePath(`/lists/${listId}`);
}

export async function importFromJson(jsonData: unknown) {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) throw new Error("Unauthorized");
  console.log("quauaaaa");

  const { parseTraktJson } = await import("@/lib/import/trakt-parser");
  const parsed = parseTraktJson(jsonData);

  // Create the list
  const { data: lists } = await supabase
    .from("lists")
    .select("position")
    .eq("user_id", user.id)
    .order("position", { ascending: false })
    .limit(1);

  const nextPosition = (lists?.[0]?.position ?? -1) + 1;

  const { data: list, error: listError } = await supabase
    .from("lists")
    .insert({
      user_id: user.id,
      name: parsed.name,
      description: parsed.description || null,
      is_public: parsed.is_public,
      position: nextPosition,
    })
    .select()
    .single();

  if (listError) throw new Error(listError.message);

  // Resolve TMDB data for all shows concurrently in batches of 15
  // (avoids sequential timeout while respecting TMDB rate limits)
  type ResolvedShow = {
    show: (typeof parsed.shows)[0];
    foundShow: {
      tmdb_id: number;
      title: string;
      poster_path: string | null;
      first_air_date: string | null;
      overview: string | null;
    } | null;
  };

  async function resolveTmdb(show: (typeof parsed.shows)[0]): Promise<ResolvedShow> {
    let foundShow: ResolvedShow["foundShow"] = null;
    if (show.imdb_id) {
      try {
        const result = await findByImdbId(show.imdb_id);
        if (result) {
          foundShow = { tmdb_id: result.id, title: result.name, poster_path: result.poster_path, first_air_date: result.first_air_date || null, overview: result.overview || null };
        }
      } catch { /* fall through */ }
    }
    if (!foundShow) {
      try {
        const data = await searchShows(show.title);
        const first = data.results?.[0];
        if (first) {
          foundShow = { tmdb_id: first.id, title: first.name, poster_path: first.poster_path, first_air_date: first.first_air_date || null, overview: first.overview || null };
        }
      } catch { /* ignore */ }
    }
    return { show, foundShow };
  }

  const BATCH_SIZE = 15;
  const resolvedShows: ResolvedShow[] = [];
  for (let i = 0; i < parsed.shows.length; i += BATCH_SIZE) {
    const batch = parsed.shows.slice(i, i + BATCH_SIZE);
    const results = await Promise.allSettled(batch.map(resolveTmdb));
    for (const r of results) {
      if (r.status === "fulfilled") resolvedShows.push(r.value);
    }
  }

  // Insert shows and list_items
  let position = 0;
  for (const { show, foundShow } of resolvedShows) {
    try {
      let dbShowId: string | null = null;
      const tmdbId = foundShow?.tmdb_id ?? Math.abs(show.title.split("").reduce((a, c) => a + c.charCodeAt(0), 0));

      let { data: existingShow } = await supabase.from("shows").select("id").eq("tmdb_id", tmdbId).single();

      if (!existingShow) {
        const { data: newShow } = await supabase
          .from("shows")
          .insert({
            tmdb_id: tmdbId,
            imdb_id: show.imdb_id,
            title: foundShow?.title || show.title,
            poster_path: foundShow?.poster_path ?? null,
            first_air_date: foundShow?.first_air_date ?? null,
            overview: foundShow?.overview ?? null,
          })
          .select("id")
          .single();
        existingShow = newShow;
      }

      dbShowId = existingShow?.id ?? null;
      if (dbShowId) {
        await supabase.from("list_items").insert({ list_id: list.id, show_id: dbShowId, position });
        position++;
      }
    } catch (e) {
      console.error(`Failed to save show: ${show.title}`, e);
    }
  }

  revalidatePath("/lists");
  return { listId: list.id, importedCount: position };
}
